#!/bin/sh
# Bar primitive demo + long-text truncation. Emits one frame and exits.
# IMPORTANT: each printf line below is ONE NDJSON message — the frame JSON
# must be a single line with no embedded newlines.

printf '%s\n' \
'{"type":"title","value":"Bars demo"}' \
'{"type":"frame","root":{"type":"vstack","gap":6,"pad":12,"children":[{"type":"text","value":"Load","weight":"bold","size":14},{"type":"hstack","gap":8,"children":[{"type":"text","value":"CPU"},{"type":"bar","value":0.72,"max":1.0,"width":160,"height":8,"color":"#5fa1ff"}]},{"type":"hstack","gap":8,"children":[{"type":"text","value":"MEM"},{"type":"bar","value":0.41,"max":1.0,"width":160,"height":8,"color":"#5fd47a"}]},{"type":"hstack","gap":8,"children":[{"type":"text","value":"DISK"},{"type":"bar","value":0.93,"max":1.0,"width":160,"height":8,"color":"#e07a5f"}]},{"type":"divider"},{"type":"text","value":"Truncation: this is a deliberately very long single line that used to overflow the pane and now ellipsizes neatly","color":"#aab"},{"type":"divider"},{"type":"text","value":"Mini sparkline (hstack of skinny bars)","weight":"bold"},{"type":"hstack","gap":2,"children":[{"type":"bar","value":0.2,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.5,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.9,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.7,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.4,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.6,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.8,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.3,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.95,"max":1.0,"width":6,"height":24,"color":"#7090b0"},{"type":"bar","value":0.55,"max":1.0,"width":6,"height":24,"color":"#7090b0"}]}]}}'
